    }
  }
];

const text = ($json.message_text || '').trim();
const qty = parseInt(text, 10);

const ctx = $json.context_json ?? {};
const pending = ctx.pending_item ?? null;

if (!pending || !Number.isInteger(qty) || qty <= 0) {
  return [
    {
      json: {
        ...$json,
        reply_text: 'Por favor indícame una cantidad válida, por ejemplo: 1, 2 o 3.',
        new_flow: 'delivery',
        new_step: 'awaiting_quantity',
        context_json: ctx
      }
    }
  ];
}

const lineSubtotal = Number((pending.price * qty).toFixed(2));

const cart = Array.isArray(ctx.cart) ? ctx.cart : [];
cart.push({
  item_code: pending.code,
  item_name: pending.name,
  quantity: qty,
  unit_price: pending.price,
  line_subtotal: lineSubtotal,
  configuration: null,
  extras: []
});

ctx.cart = cart;
delete ctx.pending_item;
ctx.flow = 'delivery';
ctx.step = 'awaiting_more_items';
ctx.intent = 'delivery_order';

return [
  {
    json: {
      ...$json,
      reply_text: `Perfecto, agregué ${qty} ${pending.name} a tu pedido. ¿Deseas agregar algo más?`,
      new_flow: 'delivery',
      new_step: 'awaiting_more_items',
      context_json: ctx
    }
  }
];

const text = (($json.normalized_value || $json.message_text || '') + '').trim().toLowerCase();
const ctx = $json.context_json ?? {};

const noWords = ['no', 'no gracias', 'eso es todo', 'nada más', 'nada mas', 'ya', 'listo'];
const yesWords = ['si', 'sí', 'quiero más', 'quiero mas', 'agregar', 'agregar más', 'agregar mas', 'yes'];

if (noWords.some(w => text.includes(w))) {
  ctx.flow = 'delivery';
  ctx.step = 'awaiting_customer_name';
  ctx.intent = 'delivery_order';

  return [
    {
