const original = $('When Executed by Another Workflow').first().json;
const guard = $('Parse Guard JSON - Delivery').first().json;

const ctx = original.context_json ?? {};
const step = guard.target_step || original.current_step;
const value = guard.normalized_value;

let reply_text = '';
let new_step = step;
let apply_action = 'reply_now';

switch (step) {
  case 'awaiting_product_selection':
    if (value === 'start_order') {
      ctx.flow = 'delivery';
      ctx.step = 'awaiting_product_selection';
      ctx.intent = 'delivery_order';

      reply_text = '¡Claro! Te ayudo con tu pedido. Puedes elegir opciones como Chaufa de Pollo, Chaufa de Chancho, Chaufa de Langostinos, Chaufa Meloso, Chaufa Salao, Chaufa Picón, Mostrazo, Acevichado, Veggie o Ármalo Taypá. ¿Cuál deseas pedir?';
      new_step = 'awaiting_product_selection';
      apply_action = 'reply_now';
    } else {
      apply_action = 'detect_product';
    }
    break;

  case 'awaiting_more_items':
    if (value === 'yes' || value === 'yes_product') {
      ctx.flow = 'delivery';
      ctx.step = 'awaiting_product_selection';
      ctx.intent = 'delivery_order';

      reply_text = 'Perfecto. Indícame qué otro producto deseas agregar.';
      new_step = 'awaiting_product_selection';
      apply_action = 'reply_now';
    } else if (value === 'no') {
      ctx.flow = 'delivery';
      ctx.step = 'awaiting_customer_name';
      ctx.intent = 'delivery_order';

      reply_text = 'Perfecto. ¿A nombre de quién registramos el pedido?';
      new_step = 'awaiting_customer_name';
      apply_action = 'reply_now';
    } else {
      ctx.flow = 'delivery';
      ctx.step = 'awaiting_more_items';
      ctx.intent = 'delivery_order';

      reply_text = '¿Deseas agregar algo más a tu pedido? Puedes responder por ejemplo: "sí" o "no, eso es todo".';
      new_step = 'awaiting_more_items';
      apply_action = 'reply_now';
    }
    break;

  default:
    apply_action = 'reply_now';
    reply_text = 'Continuemos con tu pedido.';
    break;
}

return [{
  json: {
    ...original,
    normalized_value: value,
    guard_kind: guard.kind,
    target_step: step,
    apply_action,
    reply_text,
    new_flow: 'delivery',
    new_step,
    context_json: ctx
  }
}];
